// 초기화 파라미터 설정
var initializeParameter = new InitializeParameter()
{
    Protocol = EProtocol.ModbusTcp,
    SocketIPAddress = "127.0.0.1",
    SocketPortNumber = 502
};

// 라이브러리 초기화
var comm = new DeviceProtocolModbus();
int readRetryCount = 2;
int readTimeout = 1000;
if (comm.Initialize(initializeParameter, readRetryCount, readTimeout) == false)
{
    // 초기화 실패
    return;
}

// 라이브러리 정리
comm.DeInitialize();
return;

var comm = new DeviceProtocolModbus();
// DLL 버전 정보 읽기
string version = comm.GetVersion(bReflesh: true);
Console.WriteLine($"DLL 버전: {version}");
return;

